<template>
  <div class="asset-list">
    <el-card>
      <div slot="header" style="display: flex; justify-content: space-between; align-items: center">
        <span>IT资产管理</span>
        <el-button type="primary" size="small" icon="el-icon-plus" @click="handleAdd">新增资产</el-button>
      </div>

      <el-tabs v-model="activeTab" @tab-click="handleTabClick">
        <el-tab-pane label="全部" name="all" />
        <el-tab-pane
          v-for="region in regions"
          :key="region.id"
          :label="region.name"
          :name="String(region.id)"
        />
      </el-tabs>

      <el-table :data="assets" border stripe>
        <el-table-column prop="computer_name" label="计算机名" />
        <el-table-column prop="ip_address" label="IP地址" />
        <el-table-column prop="os_type" label="操作系统" />
        <el-table-column prop="purpose" label="用途" />
        <el-table-column prop="registration_no" label="资产登记号" />
        <el-table-column prop="status" label="状态" width="80">
          <template slot-scope="scope">
            <el-tag :type="statusType(scope.row.status)" size="small">{{ scope.row.status }}</el-tag>
          </template>
        </el-table-column>
        <el-table-column label="操作" width="200">
          <template slot-scope="scope">
            <el-button size="mini" @click="handleEdit(scope.row)">编辑</el-button>
            <el-button size="mini" type="danger" @click="handleDelete(scope.row)">删除</el-button>
          </template>
        </el-table-column>
      </el-table>
    </el-card>

    <asset-form
      :visible.sync="formVisible"
      :edit-data="editData"
      :regions="regions"
      @success="fetchData"
    />
  </div>
</template>

<script>
import { getAssets, deleteAsset } from '@/api/asset'
import { getRegions } from '@/api/region'
import AssetForm from './AssetForm.vue'

export default {
  name: 'AssetList',
  components: { AssetForm },
  data() {
    return {
      assets: [],
      regions: [],
      activeTab: 'all',
      formVisible: false,
      editData: null
    }
  },
  mounted() {
    this.fetchData()
    this.fetchRegions()
  },
  methods: {
    async fetchData() {
      try {
        const regionId = this.activeTab === 'all' ? null : this.activeTab
        const res = await getAssets(regionId)
        this.assets = res.data || []
      } catch (e) {
        console.error(e)
      }
    },
    async fetchRegions() {
      try {
        const res = await getRegions()
        this.regions = res.data || []
      } catch (e) {
        console.error(e)
      }
    },
    handleTabClick() {
      this.fetchData()
    },
    handleAdd() {
      this.editData = null
      this.formVisible = true
    },
    handleEdit(row) {
      this.editData = { ...row }
      this.formVisible = true
    },
    handleDelete(row) {
      this.$confirm('确定要删除该资产吗？', '提示', { type: 'warning' }).then(async () => {
        try {
          await deleteAsset(row.id)
          this.$message.success('删除成功')
          this.fetchData()
        } catch (e) {
          console.error(e)
        }
      }).catch(() => {})
    },
    statusType(status) {
      switch (status) {
        case '在用': return 'success'
        case '闲置': return 'warning'
        case '报废': return 'danger'
        default: return 'info'
      }
    }
  }
}
</script>
