<template>
  <el-dialog :title="isEdit ? '编辑资产' : '新增资产'" :visible.sync="dialogVisible" width="600px" @close="handleClose">
    <el-form :model="form" :rules="rules" ref="formRef" label-width="100px">
      <el-form-item label="计算机名" prop="computer_name">
        <el-input v-model="form.computer_name" placeholder="请输入计算机名" />
      </el-form-item>
      <el-form-item label="所属区域" prop="region_id">
        <el-select v-model="form.region_id" placeholder="请选择区域" style="width: 100%">
          <el-option v-for="r in regions" :key="r.id" :label="r.name" :value="r.id" />
        </el-select>
      </el-form-item>
      <el-form-item label="IP地址">
        <el-input v-model="form.ip_address" placeholder="请输入IP地址" />
      </el-form-item>
      <el-form-item label="操作系统" prop="os_type">
        <el-select v-model="form.os_type" placeholder="请选择操作系统" filterable allow-create style="width: 100%">
          <el-option label="Windows 11" value="Windows 11" />
          <el-option label="Windows 10" value="Windows 10" />
          <el-option label="Windows 7" value="Windows 7" />
          <el-option label="macOS" value="macOS" />
          <el-option label="Linux" value="Linux" />
          <el-option label="其他" value="其他" />
        </el-select>
      </el-form-item>
      <el-form-item label="用途">
        <el-input v-model="form.purpose" placeholder="请输入用途" />
      </el-form-item>
      <el-form-item label="资产登记号">
        <el-input v-model="form.registration_no" placeholder="请输入资产登记号" />
      </el-form-item>
      <el-form-item label="状态">
        <el-select v-model="form.status" style="width: 100%">
          <el-option label="在用" value="在用" />
          <el-option label="闲置" value="闲置" />
          <el-option label="报废" value="报废" />
        </el-select>
      </el-form-item>
      <el-form-item label="备注">
        <el-input v-model="form.remark" type="textarea" :rows="3" placeholder="请输入备注" />
      </el-form-item>
    </el-form>
    <span slot="footer">
      <el-button @click="dialogVisible = false">取消</el-button>
      <el-button type="primary" @click="handleSubmit">确定</el-button>
    </span>
  </el-dialog>
</template>

<script>
import { createAsset, updateAsset } from '@/api/asset'

export default {
  name: 'AssetForm',
  props: {
    visible: { type: Boolean, default: false },
    editData: { type: Object, default: null },
    regions: { type: Array, default: () => [] }
  },
  data() {
    return {
      form: this.getDefaultForm(),
      rules: {
        computer_name: [{ required: true, message: '请输入计算机名', trigger: 'blur' }],
        region_id: [{ required: true, message: '请选择区域', trigger: 'change' }],
        os_type: [{ required: true, message: '请选择操作系统', trigger: 'change' }]
      }
    }
  },
  computed: {
    dialogVisible: {
      get() { return this.visible },
      set(val) { this.$emit('update:visible', val) }
    },
    isEdit() {
      return this.editData !== null
    }
  },
  watch: {
    visible(val) {
      if (val && this.editData) {
        this.form = { ...this.editData }
      } else if (val) {
        this.form = this.getDefaultForm()
      }
    }
  },
  methods: {
    getDefaultForm() {
      return {
        computer_name: '',
        region_id: null,
        ip_address: '',
        os_type: '',
        purpose: '',
        registration_no: '',
        status: '在用',
        remark: ''
      }
    },
    handleSubmit() {
      this.$refs.formRef.validate(async valid => {
        if (!valid) return
        try {
          if (this.isEdit) {
            await updateAsset(this.form.id, this.form)
            this.$message.success('更新成功')
          } else {
            await createAsset(this.form)
            this.$message.success('创建成功')
          }
          this.dialogVisible = false
          this.$emit('success')
        } catch (e) {
          console.error(e)
        }
      })
    },
    handleClose() {
      this.form = this.getDefaultForm()
    }
  }
}
</script>
